function filterCards(containerSelector,buttonSelector,itemSelector){const container=document.querySelector(containerSelector);if(!container)return;document.querySelectorAll(buttonSelector).forEach(btn=>btn.addEventListener("click",()=>{document.querySelectorAll(buttonSelector).forEach(b=>b.classList.remove("active"));btn.classList.add("active");const filter=btn.dataset.filter;container.querySelectorAll(itemSelector).forEach(card=>{card.classList.toggle("hide",filter!=="all"&&!card.dataset.filter.includes(filter))})}))}
